pub fn render_help(output: &Output) -> Result<()> {
    if !output.is_styled() {
        render_help_plain();
        return Ok(());
    }

    let theme = &output.theme;

    // Logo/Title
    let title = format!(
        "[{} bold]xf[/] - X Archive Search Tool",
        theme.primary
    );
    output.print(&title);
    output.print("");

    // Usage section
    let usage = format!(
        "[{}]USAGE:[/]\n    [{}]xf[/] [OPTIONS] <COMMAND>",
        theme.heading,
        theme.primary
    );
    output.print(&usage);
    output.print("");

    // Commands section
    let commands = [
        ("search <QUERY>", "Search your X archive"),
        ("stats", "Show archive statistics"),
        ("index", "Build or rebuild search index"),
        ("doctor", "Check system health"),
        ("repl", "Interactive search mode"),
        ("list-hashtags", "List hashtags by frequency"),
        ("list-mentions", "List mentions by frequency"),
        ("completions <SHELL>", "Generate shell completions"),
    ];

    output.print(&format!("[{}]COMMANDS:[/]", theme.heading));
    for (cmd, desc) in &commands {
        output.print(&format!(
            "    [{} bold]{:20}[/] {}",
            theme.primary, cmd, desc
        ));
    }
    output.print("");

    // Options section
    let options = [
        ("-h, --help", "Print help information"),
        ("-V, --version", "Print version"),
        ("-q, --quiet", "Suppress non-error output"),
        ("-v, --verbose", "Show extra details (-vv for debug)"),
        ("--format <FORMAT>", "Output format: text, json, csv"),
        ("--theme <THEME>", "Color theme: dark, light, no-color"),
        ("--archive <PATH>", "Path to X archive"),
    ];

    output.print(&format!("[{}]OPTIONS:[/]", theme.heading));
    for (opt, desc) in &options {
        output.print(&format!(
            "    [{} bold]{:24}[/] {}",
            theme.secondary, opt, desc
        ));
    }
    output.print("");

    // Examples section
    output.print(&format!("[{}]EXAMPLES:[/]", theme.heading));

    let examples = [
        ("# Search for tweets about rust", "xf search \"rust programming\""),
        ("# Search only your own tweets", "xf search \"conference\" --type tweets"),
        ("# Search with date filter", "xf search \"meeting\" --since \"2024-01-01\""),
        ("# Interactive search mode", "xf repl"),
        ("# Export results as JSON", "xf search \"project\" --format json"),
        ("# Check system health", "xf doctor"),
    ];

    for (comment, command) in &examples {
        output.print(&format!("    [{}]{}[/]", theme.muted, comment));
        output.print(&format!("    [{}]{}[/]", theme.primary, command));
        output.print("");
    }

    // Footer with more info
    output.print(&format!(
        "[{}]For more information, visit: https://github.com/user/xf[/]",
        theme.muted
    ));

    Ok(())
}

