### Output Extension for stderr
```rust
// Add to Output impl
impl Output {
    /// Print a renderable to stderr (for instructions that shouldn't interfere with piped output)
    pub fn eprint_renderable(&self, renderable: &impl Renderable) {
        if self.is_styled() {
            // Use console's stderr mode
            let mut stderr = std::io::stderr();
            let rendered = self.console.render(renderable);
            writeln!(stderr, "{}", rendered).ok();
        } else {
            eprintln!("{}", renderable.to_plain_text());
        }
    }

    /// Print to stderr
    pub fn eprint(&self, text: &str) {
        if self.is_styled() {
            eprintln!("{}", self.console.render_str(text));
        } else {
            eprintln!("{}", strip_markup(text));
        }
    }
}
