### E2E Test Script
```bash
#!/bin/bash
set -euo pipefail
LOG=/tmp/xf-help-completions-e2e.log
echo "[$(date -Iseconds)] Starting Help/Completions E2E tests" | tee "$LOG"

# Test 1: Help command
echo "Test 1: Help command" | tee -a "$LOG"
HELP_OUT=$(xf --help 2>&1)
echo "$HELP_OUT" | head -20 | tee -a "$LOG"
if echo "$HELP_OUT" | grep -qiE 'usage|command|option'; then
    echo "  PASS: Help shows expected sections" | tee -a "$LOG"
else
    echo "  FAIL: Help missing expected content" | tee -a "$LOG"
    exit 1
fi

# Test 2: Subcommand help
echo "Test 2: Subcommand help" | tee -a "$LOG"
SEARCH_HELP=$(xf search --help 2>&1)
echo "$SEARCH_HELP" | head -10 | tee -a "$LOG"
if echo "$SEARCH_HELP" | grep -qiE 'search|query'; then
    echo "  PASS: Subcommand help works" | tee -a "$LOG"
fi

# Test 3: Completions generate for each shell
echo "Test 3: Completions generation" | tee -a "$LOG"
for shell in bash zsh fish; do
    COMP_OUT=$(xf completions "$shell" 2>&1)
    COMP_LINES=$(echo "$COMP_OUT" | wc -l)
    if [ "$COMP_LINES" -gt 10 ]; then
        echo "  PASS: $shell completions generated ($COMP_LINES lines)" | tee -a "$LOG"
    else
        echo "  WARN: $shell completions may be incomplete" | tee -a "$LOG"
    fi
done

# Test 4: Completions can be piped (stdout is completion, stderr is instructions)
echo "Test 4: Completions pipe correctly" | tee -a "$LOG"
COMP_STDOUT=$(xf completions bash 2>/dev/null)
COMP_STDERR=$(xf completions bash 2>&1 >/dev/null)
if [ -n "$COMP_STDOUT" ]; then
    echo "  PASS: Completions go to stdout" | tee -a "$LOG"
fi
if echo "$COMP_STDERR" | grep -qiE 'install|add|source'; then
    echo "  PASS: Instructions go to stderr" | tee -a "$LOG"
fi

# Test 5: Piped help output clean
echo "Test 5: Piped help output" | tee -a "$LOG"
PIPED=$(xf --help 2>&1 | cat)
if echo "$PIPED" | grep -qP '\x1b\['; then
    echo "  FAIL: ANSI in piped help" | tee -a "$LOG"
    exit 1
fi
echo "  PASS: Piped help clean" | tee -a "$LOG"

# Test 6: Help includes examples
echo "Test 6: Help examples" | tee -a "$LOG"
if echo "$HELP_OUT" | grep -qiE 'example|xf search'; then
    echo "  PASS: Help includes examples" | tee -a "$LOG"
else
    echo "  INFO: Examples format may vary" | tee -a "$LOG"
fi

# Test 7: Completions have function definitions
echo "Test 7: Completion content" | tee -a "$LOG"
BASH_COMP=$(xf completions bash 2>/dev/null)
if echo "$BASH_COMP" | grep -qE '_xf|complete|compgen'; then
    echo "  PASS: Bash completions have proper structure" | tee -a "$LOG"
fi

ZSH_COMP=$(xf completions zsh 2>/dev/null)
if echo "$ZSH_COMP" | grep -qE '#compdef|_arguments|_xf'; then
    echo "  PASS: Zsh completions have proper structure" | tee -a "$LOG"
fi

FISH_COMP=$(xf completions fish 2>/dev/null)
if echo "$FISH_COMP" | grep -qE 'complete -c xf'; then
    echo "  PASS: Fish completions have proper structure" | tee -a "$LOG"
fi

# Test 8: Help performance
echo "Test 8: Help performance" | tee -a "$LOG"
START=$(date +%s%N)
xf --help > /dev/null 2>&1
END=$(date +%s%N)
DURATION=$(( (END - START) / 1000000 ))
if [ "$DURATION" -lt 500 ]; then
    echo "  PASS: Help renders in ${DURATION}ms (< 500ms)" | tee -a "$LOG"
else
    echo "  WARN: Help slow: ${DURATION}ms" | tee -a "$LOG"
fi

echo "[$(date -Iseconds)] All Help/Completions tests passed" | tee -a "$LOG"
