use clap::ValueEnum;
use std::io::Write;

/// Supported shells for completion generation
#[derive(Clone, Copy, Debug, PartialEq, Eq, ValueEnum)]
pub enum Shell {
    /// Bourne Again SHell
    Bash,
    /// Z Shell
    Zsh,
    /// Friendly Interactive SHell
    Fish,
    /// PowerShell
    PowerShell,
    /// Elvish shell
    Elvish,
}

impl Shell {
    /// Get the shell name as a string
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Bash => "bash",
            Self::Zsh => "zsh",
            Self::Fish => "fish",
            Self::PowerShell => "powershell",
            Self::Elvish => "elvish",
        }
    }

    /// Get the typical config file for this shell
    pub fn config_file(&self) -> &'static str {
        match self {
            Self::Bash => "~/.bashrc",
            Self::Zsh => "~/.zshrc",
            Self::Fish => "~/.config/fish/config.fish",
            Self::PowerShell => "$PROFILE",
            Self::Elvish => "~/.elvish/rc.elv",
        }
    }

    /// Get installation instructions for this shell
    pub fn install_instructions(&self) -> &'static str {
        match self {
            Self::Bash => "Add to ~/.bashrc:\n  source <(xf completions bash)",
            Self::Zsh => "Add to ~/.zshrc:\n  source <(xf completions zsh)\n\nOr for oh-my-zsh:\n  xf completions zsh > ~/.oh-my-zsh/completions/_xf",
            Self::Fish => "Run once:\n  xf completions fish | source\n\nOr persist:\n  xf completions fish > ~/.config/fish/completions/xf.fish",
            Self::PowerShell => "Add to $PROFILE:\n  xf completions powershell | Out-String | Invoke-Expression",
            Self::Elvish => "Add to ~/.elvish/rc.elv:\n  eval (xf completions elvish | slurp)",
        }
    }
}
