pub fn render_mention_list(mentions: &[(String, usize)], output: &Output, theme: &Theme) {
    let total: usize = mentions.iter().map(|(_, c)| c).sum();

    let table = ListTable::new("👤 Mentions", mentions.to_vec())
        .theme(theme.clone())
        .add_column(
            TableColumn::new("User", |(user, _)| format!("@{}", user))
                .style(Style::new().foreground(theme.mention))
        )
        .add_column(
            TableColumn::new("Count", |(_, count)| count.to_string())
                .justify(JustifyMethod::Right)
                .sortable(|(_, count)| *count as i64)
        )
        .add_column(
            TableColumn::new("%", move |(_, count)| {
                if total > 0 {
                    format!("{:.1}%", (*count as f64 / total as f64) * 100.0)
                } else {
                    "—".to_string()
                }
            })
            .justify(JustifyMethod::Right)
        )
        .sort_by(1, true);

    table.render(output);
}
