#[test]
fn test_mrl_dimension_sweep_quality() {
    // Test search quality at each MRL dimension to verify:
    // 1. Re-normalization is correctly applied in the index
    // 2. Quality degrades gracefully
    // 3. Even low dimensions still produce usable results

    let corpus = load_test_corpus();
    let queries = load_test_queries();

    let mrl_models = ["static-mrl", "nomic", "embedding-gemma"];
    let dimensions = [64, 128, 256, 512, 768, 1024];

    for model in mrl_models {
        let mut dim_results: Vec<(usize, f64)> = Vec::new();

        for &dims in &dimensions {
            // Skip dims larger than model supports
            let max_dims = match model {
                "static-mrl" => 1024,
                "nomic" => 768,
                "embedding-gemma" => 1024,
                _ => continue,
            };
            if dims > max_dims { continue; }

            // Build index at this dimension
            let index = build_index_with_dims(&corpus, model, dims).unwrap();

            // Measure quality
            let mut mrr_sum = 0.0;
            for query in &queries {
                mrr_sum += compute_mrr(&index, &query.text, SearchOpts::semantic(), &query.relevant_ids);
            }
            let avg_mrr = mrr_sum / queries.len() as f64;
            dim_results.push((dims, avg_mrr));

            tracing::info!(
                model = model,
                dims = dims,
                mrr = avg_mrr,
                "MRL sweep: quality at dimension"
            );
        }

        // Verify monotonic quality improvement (with some tolerance)
        for window in dim_results.windows(2) {
            let (d1, q1) = window[0];
            let (d2, q2) = window[1];
            // Higher dims should give equal or better quality
            assert!(q2 >= q1 * 0.85,
                "{}: quality at dims={} ({:.3}) should not be much worse than dims={} ({:.3})",
                model, d2, q2, d1, q1);
        }

        // Even at lowest dimension, quality should be non-trivial
        if let Some(&(dims, quality)) = dim_results.first() {
            assert!(quality > 0.1,
                "{}: even at {} dims, MRR should be >0.1, got {:.3}",
                model, dims, quality);
        }
    }
}

