#[test]
fn test_binary_quantization_search() {
    // Test the two-phase retrieval: binary hamming -> FP32 rescore
    let corpus = load_test_corpus();
    let queries = load_test_queries();

    // Build normal index
    let normal_index = build_index(&corpus, "nomic").unwrap();

    // Build binary-quantized index
    let binary_index = build_binary_index(&corpus, "nomic").unwrap();

    let mut normal_mrr = 0.0;
    let mut binary_mrr = 0.0;

    for query in &queries {
        normal_mrr += compute_mrr(&normal_index, &query.text, SearchOpts::semantic(), &query.relevant_ids);
        binary_mrr += compute_mrr(&binary_index, &query.text, SearchOpts::binary_rescore(), &query.relevant_ids);
    }

    let n = queries.len() as f64;
    tracing::info!(
        normal_mrr = normal_mrr / n,
        binary_mrr = binary_mrr / n,
        quality_retained_pct = (binary_mrr / normal_mrr) * 100.0,
        "Binary quantization quality"
    );

    // Binary+rescore should retain at least 90% of full quality
    assert!(binary_mrr >= normal_mrr * 0.85,
        "Binary quantization should retain 85%+ quality: {:.3} vs {:.3}",
        binary_mrr / n, normal_mrr / n);
}

#[test]
fn test_binary_index_size_reduction() {
    let corpus = load_test_corpus_medium(); // 1000 docs

    let normal_index = build_index(&corpus, "nomic").unwrap();
    let binary_index = build_binary_index(&corpus, "nomic").unwrap();

    let normal_bytes = normal_index.embedding_storage_bytes();
    let binary_bytes = binary_index.embedding_storage_bytes();
    let compression = normal_bytes as f64 / binary_bytes as f64;

    tracing::info!(
        normal_bytes = normal_bytes,
        binary_bytes = binary_bytes,
        compression = format!("{:.1}x", compression),
        "Binary quantization compression"
    );

    // 768 dims * 4 bytes = 3072 bytes vs 768 / 8 = 96 bytes = 32x
    assert!(compression > 20.0,
        "Binary should give >20x compression, got {:.1}x", compression);
}

#[test]
fn test_binary_search_latency() {
    let corpus = load_test_corpus_medium(); // 1000 docs
    let binary_index = build_binary_index(&corpus, "nomic").unwrap();
    let normal_index = build_index(&corpus, "nomic").unwrap();
    let query = "test query for latency";

    // Warmup
    for _ in 0..5 {
        normal_index.search(query, SearchOpts::semantic()).unwrap();
        binary_index.search(query, SearchOpts::binary_rescore()).unwrap();
    }

    let start = Instant::now();
    for _ in 0..50 { normal_index.search(query, SearchOpts::semantic()).unwrap(); }
    let normal_ms = start.elapsed().as_millis() as f64 / 50.0;

    let start = Instant::now();
    for _ in 0..50 { binary_index.search(query, SearchOpts::binary_rescore()).unwrap(); }
    let binary_ms = start.elapsed().as_millis() as f64 / 50.0;

    tracing::info!(
        normal_ms = normal_ms,
        binary_ms = binary_ms,
        speedup = format!("{:.1}x", normal_ms / binary_ms),
        "Binary quantization latency"
    );

    // Binary hamming should be faster than FP32 cosine
    assert!(binary_ms <= normal_ms * 1.5,
        "Binary should not be much slower: {}ms vs {}ms", binary_ms, normal_ms);
}
