#[test]
fn test_search_latency_regression() {
    let index = build_large_test_index(10000);
    let queries = load_test_queries();

    let mut latencies = Vec::new();
    for query in &queries {
        let start = Instant::now();
        let _ = index.search(&query.text, SearchOpts::hybrid()).unwrap();
        latencies.push(start.elapsed().as_millis() as f64);
    }

    latencies.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let p50 = latencies[latencies.len() / 2];
    let p95 = latencies[latencies.len() * 95 / 100];
    let p99 = latencies[latencies.len() * 99 / 100];

    tracing::info!(p50 = p50, p95 = p95, p99 = p99, docs = 10000, "Search latency");

    assert!(p50 < 100.0, "p50 should be <100ms for 10k docs, got {}ms", p50);
    assert!(p95 < 300.0, "p95 should be <300ms for 10k docs, got {}ms", p95);
    assert!(p99 < 500.0, "p99 should be <500ms for 10k docs, got {}ms", p99);
}

