#[test]
fn test_model_relative_quality_ordering() {
    // Verify that more capable models produce better results
    let corpus = load_test_corpus();
    let queries = load_test_queries();

    let models = ["model2vec", "static-mrl", "minilm", "bge-small", "nomic"];
    let mut model_mrrs: Vec<(&str, f64)> = Vec::new();

    for model in models {
        let index = build_index(&corpus, model).unwrap();
        let mut mrr_sum = 0.0;
        for query in &queries {
            mrr_sum += compute_mrr(&index, &query.text, SearchOpts::semantic(), &query.relevant_ids);
        }
        let avg_mrr = mrr_sum / queries.len() as f64;
        model_mrrs.push((model, avg_mrr));

        tracing::info!(model = model, mrr = avg_mrr, "Model quality");
    }

    // Log the full ranking
    model_mrrs.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap());
    for (rank, (model, mrr)) in model_mrrs.iter().enumerate() {
        tracing::info!(rank = rank + 1, model = model, mrr = mrr, "Quality ranking");
    }

    // All models should produce non-trivial results
    for (model, mrr) in &model_mrrs {
        assert!(*mrr > 0.05, "{} should have MRR > 0.05, got {:.3}", model, mrr);
    }
}
